-- CMDB Costes / Budget table
CREATE TABLE IF NOT EXISTS cmdb_costes (
    id_coste SERIAL PRIMARY KEY,
    id_activo INTEGER REFERENCES cmdb_activos(id_activo),
    concepto VARCHAR(200) NOT NULL,
    categoria VARCHAR(30) CHECK (categoria IN ('HARDWARE','SOFTWARE','CLOUD','LICENCIAS','MANTENIMIENTO','SOPORTE','RRHH','CONSULTORIA','FORMACION','OTROS')),
    tipo VARCHAR(10) CHECK (tipo IN ('CAPEX','OPEX')),
    importe NUMERIC(12,2) NOT NULL,
    moneda VARCHAR(3) DEFAULT 'EUR',
    periodicidad VARCHAR(15) DEFAULT 'MENSUAL' CHECK (periodicidad IN ('UNICO','MENSUAL','TRIMESTRAL','ANUAL')),
    fecha_inicio DATE,
    fecha_fin DATE,
    proveedor VARCHAR(100),
    centro_coste VARCHAR(50),
    id_proyecto VARCHAR(50),
    notas TEXT,
    created_at TIMESTAMP DEFAULT NOW()
);

-- Seed data: ~40 cost entries linked to existing assets and projects
